const response = await fetch('https://api.example.com/posts', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer MY_TOKEN'
  },
  body: JSON.stringify({ title: 'Hello', body: 'World' })
});
const data = await response.json();

